class Solution:
    def canMakeSubsequence(self, str1: str, str2: str) -> bool:
        # Two pointers approach to check if str2 is a subsequence of str1 after at most one operation
        i, j = 0, 0
        n, m = len(str1), len(str2)

        while i < n and j < m:
            # Check if current character in str1 can be incremented to match str2[j]
            if ord(str1[i]) + 1 == ord(str2[j]) or (str1[i] == 'z' and str2[j] == 'a'):
                j += 1
            i += 1

        return j == m
